function solve(nums, k) {
    const N = nums.length;
    const INF = Number.MAX_SAFE_INTEGER;

    // Maximum possible peaks is floor(N/2).
    if (k > Math.floor(N / 2)) {
        return -1;
    }
    if (k === 0) {
        return 0;
    }

    // Helper function to calculate the required cost to make index i a peak, 
    // assuming neighbors are NOT increased (i.e., they are original values).
    // This cost calculation is used only when i is selected in the DP.
    const calculateCost = (i, n, arr) => {
        const prev = arr[(i - 1 + n) % n];
        const next = arr[(i + 1) % n];
        const required = Math.max(prev, next) + 1;
        return Math.max(0, required - arr[i]);
    };

    // --- Case A: Index 0 is NOT selected (s_0 = 0) ---
    // DP[i][j][s]: Min cost considering prefix 0..i, having j peaks, where s=1 if i is selected, s=0 otherwise.
    // Size: N x (K+1) x 2
    let dpA = Array(N).fill(0).map(() => 
        Array(k + 1).fill(0).map(() => [INF, INF])
    );

    // Base case i=0: 0 is not selected (s_0=0). Cost 0, 0 peaks.
    dpA[0][0][0] = 0;

    for (let i = 1; i < N; i++) {
        // Cost C_i relies on neighbors, which we assume are original values since they are not selected.
        const C_i = calculateCost(i, N, nums);

        for (let j = 0; j <= k; j++) {
            // 1. Current index i is NOT selected (s_i = 0)
            // Can transition from i-1 being selected or not.
            dpA[i][j][0] = Math.min(dpA[i-1][j][0], dpA[i-1][j][1]);

            // 2. Current index i IS selected (s_i = 1)
            if (j > 0) {
                // Must transition from i-1 NOT selected (s_{i-1} = 0).
                if (dpA[i-1][j-1][0] !== INF) {
                    dpA[i][j][1] = dpA[i-1][j-1][0] + C_i;
                }
            }
        }
    }

    let minCostA = Math.min(dpA[N - 1][k][0], dpA[N - 1][k][1]);


    // --- Case B: Index 0 IS selected (s_0 = 1) ---

    // Cost C_0. Neighbors are N-1 and 1.
    const C_0 = calculateCost(0, N, nums);

    // We must ensure s_1 = 0 and s_{N-1} = 0.

    let dpB = Array(N).fill(0).map(() => 
        Array(k + 1).fill(0).map(() => [INF, INF])
    );

    // Base case i=0: 0 is selected (s_0=1). 1 peak achieved.
    dpB[0][1][1] = C_0;

    for (let i = 1; i < N; i++) {
        const C_i = calculateCost(i, N, nums);

        for (let j = 0; j <= k; j++) {
            // 1. Current index i is NOT selected (s_i = 0)
            dpB[i][j][0] = Math.min(dpB[i-1][j][0], dpB[i-1][j][1]);

            // 2. Current index i IS selected (s_i = 1)
            if (j > 0) {
                // Constraint: s_{i-1} must be 0.
                dpB[i][j][1] = dpB[i-1][j-1][0] + C_i;
            }
        }
    }

    // Enforce boundary constraints for Case B: s_1=0 and s_{N-1}=0
    let minCostB = INF;

    if (N === 2) {
        // N=2, K=1. s_0=1. s_1 must be 0.
        // DP[1][1][0] must be the result.
        if (dpB[1][1][0] !== INF) {
             minCostB = dpB[1][1][0];
        }
    } else if (N > 2) {
        // We must have s_{N-1} = 0.
        minCostB = dpB[N-1][k][0];

        // We also need to ensure s_1=0 was maintained implicitly by the transition logic.
        // Since s_0=1, DP[1][j][1] would have been set to INF if we strictly enforced the constraint in the loop.
        // Let's verify the initial setup handles s_1=0.

        // If i=1, s_1=1 implies transition from dpB[0][j-1][0], which is INF because s_0=1.
        // So DP[1][j][1] remains INF, effectively enforcing s_1=0.
    }


    const overallMinCost = Math.min(minCostA, minCostB);

    return overallMinCost === INF ? -1 : overallMinCost;
}

