import scala.math._

object Solution {
  def solve(nums: Array[Long], k: Long): Long = {
    val N = nums.length

    if (k == 0) return 0

    // Maximum possible peaks is floor(N/2).
    if (k > N / 2) return -1

    val K_int = k.toInt
    val INF = Long.MaxValue / 2 // Use a safe large number

    // Helper function to calculate the required cost to make index i a peak, 
    // assuming neighbors are NOT increased (i.e., they are original values).
    val calculateCost = (i: Int) => {
      val prev = nums[(i - 1 + N) % N]
      val next = nums[(i + 1) % N]
      val required = max(prev, next) + 1
      max(0L, required - nums(i))
    }

    // --- Case A: Index 0 is NOT selected (s_0 = 0) ---
    // DP_A[i][j][s]: Min cost considering prefix 0..i, having j peaks, where s=1 if i is selected, s=0 otherwise.
    // Size: N x (K+1) x 2
    // Initialize with INF
    val dpA = Array.fill(0)(Array.fill(0)(Array(INF, INF)))

    // Base case i=0: 0 is not selected (s_0=0). Cost 0, 0 peaks.
    dpA(0)(0)(0) = 0L

    for (i <- 1 until N) {
      val C_i = calculateCost(i)

      for (j <- 0 to K_int) {
        // 1. Current index i is NOT selected (s_i = 0)
        // Transition from i-1 being selected or not.
        dpA(i)(j)(0) = min(dpA(i-1)(j)(0), dpA(i-1)(j)(1))

        // 2. Current index i IS selected (s_i = 1)
        if (j > 0) {
          // Must transition from i-1 NOT selected (s_{i-1} = 0).
          val prevCost = dpA(i-1)(j-1)(0)
          if (prevCost != INF) {
            dpA(i)(j)(1) = prevCost + C_i
          }
        }
      }
    }

    var minCostA = min(dpA(N - 1)(K_int)(0), dpA(N - 1)(K_int)(1))

    // --- Case B: Index 0 IS selected (s_0 = 1) ---

    val C_0 = calculateCost(0)

    val dpB = Array.fill(0)(Array.fill(0)(Array(INF, INF)))

    // Base case i=0: 0 is selected (s_0=1). 1 peak achieved.
    if (K_int >= 1) {
      dpB(0)(1)(1) = C_0
    }

    for (i <- 1 until N) {
      val C_i = calculateCost(i)

      for (j <- 0 to K_int) {
        // 1. Current index i is NOT selected (s_i = 0)
        dpB(i)(j)(0) = min(dpB(i-1)(j)(0), dpB(i-1)(j)(1))

        // 2. Current index i IS selected (s_i = 1)
        if (j > 0) {
          // Constraint: s_{i-1} must be 0.
          val prevCost = dpB(i-1)(j-1)(0)
          if (prevCost != INF) {
            dpB(i)(j)(1) = prevCost + C_i
          }
        }
      }
    }

    var minCostB = INF

    if (N == 2) {
      // N=2, K=1. s_0=1. We need s_1=0.
      minCostB = dpB(1)(K_int)(0)
    } else if (N > 2) {
      // We must have s_{N-1} = 0.
      minCostB = dpB(N-1)(K_int)(0)
    }

    val overallMinCost = min(minCostA, minCostB)

    if (overallMinCost >= INF) -1L else overallMinCost
  }
}
